$pdo=obtenerConexion();try{$pdo->beginTransaction();$q=$pdo->prepare('SELECT * FROM productos WHERE id=:id AND activo=1 AND disponible=1 AND eliminado_at IS NULL FOR UPDATE');$q->execute(['id'=>$productoId]);$p=$q->fetch();if(!$p||((int)$p['stock']-(int)$p['stock_reservado'])<$cantidad)throw new RuntimeException('Stock insuficiente.');$precio=precioProducto($p,promocionVigente($pdo,$productoId));$subtotal=round($precio['final']*$cantidad,2);$descuento=round($precio['descuento']*$cantidad,2);$numero=numeroPedido();$q=$pdo->prepare("INSERT INTO pedidos(numero,usuario_id,subtotal,descuento,total,moneda,estado)VALUES(:n,:u,:s,:d,:t,:m,'pendiente')");$q->execute(['n'=>$numero,'u'=>$_SESSION['usuario_id'],'s'=>round($precio['normal']*$cantidad,2),'d'=>$descuento,'t'=>$subtotal,'m'=>$cfg['currency']]);$pedidoId=(int)$pdo->lastInsertId();$q=$pdo->prepare('INSERT INTO pedido_detalles(pedido_id,producto_id,nombre_producto,sku,cantidad,precio_normal,precio_unitario,descuento_unitario,subtotal,promocion_id)VALUES(:pedido,:producto,:nombre,:sku,:cantidad,:normal,:unitario,:descuento,:subtotal,:promo)');$q->execute(['pedido'=>$pedidoId,'producto'=>$productoId,'nombre'=>$p['nombre'],'sku'=>$p['sku'],'cantidad'=>$cantidad,'normal'=>$precio['normal'],'unitario'=>$precio['final'],'descuento'=>$precio['descuento'],'subtotal'=>$subtotal,'promo'=>$precio['promocion']['id']??null]);$pdo->prepare('UPDATE productos SET stock_reservado=stock_reservado+:c WHERE id=:id')->execute(['c'=>$cantidad,'id'=>$productoId]);registrarHistorialPedido($pdo,$pedidoId,null,'pendiente','sistema',(int)$_SESSION['usuario_id'],'Pedido creado; stock reservado.');$pdo->commit();
